import { create } from 'zustand';
import { UtilityType, Receipt } from '../types';

interface AppState {
  receipts: Receipt[];
  isLoading: boolean;
  addReceipt: (receipt: any) => Promise<void>;
  deleteReceipt: (id: string) => Promise<void>;
}

export const useStore = create<AppState>((set, get) => ({
  receipts: [],
  isLoading: false,

  addReceipt: async (receipt) => {
    const newReceipt = { ...receipt, id: Math.random().toString(36).substr(2, 9) };
    set(state => ({ receipts: [newReceipt, ...state.receipts] }));
  },

  deleteReceipt: async (id) => {
    set(state => ({ receipts: state.receipts.filter(r => r.id !== id) }));
  },
}));
